// MARK: - 3. View Model (State Management)

/// Manages the state and business logic for the NotificationsView.
final class NotificationsViewModel: ObservableObject {
    @Published var notifications: [NotificationItem] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    
    private let apiClient: APIClient
    
    init(apiClient: APIClient = APIClient()) {
        self.apiClient = apiClient
    }
    
    /// Fetches the list of notifications from the API.
    @MainActor
    func fetchNotifications() async {
        isLoading = true
        errorMessage = nil
        
        do {
            let fetchedNotifications = try await apiClient.fetchNotifications()
            // Simulate offline/caching logic: merge new data with existing,
            // prioritizing the latest status from the API.
            // For simplicity, we just replace the list here.
            self.notifications = fetchedNotifications
        } catch {
            if let apiError = error as? APIClient.APIError {
                errorMessage = apiError.localizedDescription
            } else {
                errorMessage = "Failed to load notifications. Please try again."
            }
        }
        
        isLoading = false
    }
    
    /// Marks a specific notification as read both locally and via the API.
    @MainActor
    func markAsRead(notification: NotificationItem) {
        guard let index = notifications.firstIndex(where: { $0.id == notification.id }),
              !notifications[index].isRead else { return }
        
        // Optimistic update
        notifications[index].isRead = true
        
        Task {
            do {
                try await apiClient.markAsRead(id: notification.id)
                // If API fails, we could revert the optimistic update or show a specific error
            } catch {
                // Revert optimistic update on failure
                notifications[index].isRead = false
                errorMessage = "Failed to mark notification as read."
            }
        }
    }
    
    /// Marks all unread notifications as read.
    @MainActor
    func markAllAsRead() {
        for i in notifications.indices where !notifications[i].isRead {
            notifications[i].isRead = true
            // In a real app, this would call a batch API endpoint
            Task {
                try? await apiClient.markAsRead(id: notifications[i].id)
            }
        }
    }
    
    var unreadCount: Int {
        notifications.filter { !$0.isRead }.count
    }
}

// MARK: - 4. Sub-Views

/// A single row view for a notification item.
struct NotificationRow: View {
    @State var notification: NotificationItem
    let markAsReadAction: (NotificationItem) -> Void
    
    var body: some View {
        HStack(alignment: .top) {
            // Unread indicator
            Circle()
                .fill(notification.isRead ? Color.clear : Color.accentColor)
                .frame(width: 8, height: 8)
                .padding(.top, 5)
            
            VStack(alignment: .leading, spacing: 4) {
                Text(notification.title)
                    .font(.headline)
                    .fontWeight(notification.isRead ? .regular : .semibold)
                    .foregroundColor(notification.isRead ? .secondary : .primary)
                    .accessibilityLabel("Notification title: \(notification.title)")
                
                Text(notification.body)
                    .font(.subheadline)
                    .lineLimit(2)
                    .foregroundColor(.secondary)
                    .accessibilityLabel("Notification body: \(notification.body)")
                
                Text(notification.formattedTimestamp)
                    .font(.caption)
                    .foregroundColor(.tertiary)
                    .accessibilityLabel("Received \(notification.formattedTimestamp)")
            }
            
            Spacer()
        }
        .contentShape(Rectangle()) // Make the entire row tappable
        .onTapGesture {
            // Mark as read on tap
            markAsReadAction(notification)
            // In a real app, this would also navigate to a detail view
        }
    }
}

// MARK: - 5. Main View

/// The main SwiftUI view for displaying the list of push notifications.
struct NotificationsView: View {
    // State Management: Integrate with ObservableObject
    @StateObject private var viewModel = NotificationsViewModel()
    
    // Navigation: Used for navigating to a detail view or settings
    @State private var isShowingSettings = false
    
    var body: some View {
        NavigationView {
            Group {
                if viewModel.isLoading && viewModel.notifications.isEmpty {
                    // Loading State
                    ProgressView("Loading Notifications...")
                        .accessibilityLabel("Loading notifications")
                } else if let error = viewModel.errorMessage {
                    // Error Handling State
                    VStack {
                        Image(systemName: "exclamationmark.triangle.fill")
                            .foregroundColor(.red)
                            .font(.largeTitle)
                            .padding(.bottom, 8)
                        Text("Error")
                            .font(.title2)
                        Text(error)
                            .multilineTextAlignment(.center)
                            .foregroundColor(.secondary)
                            .padding(.horizontal)
                        Button("Retry") {
                            Task { await viewModel.fetchNotifications() }
                        }
                        .padding(.top, 10)
                        .buttonStyle(.borderedProminent)
                    }
                    .padding()
                    .accessibilityElement(children: .combine)
                    .accessibilityLabel("Error loading notifications. \(error). Tap retry button.")
                } else if viewModel.notifications.isEmpty {
                    // Empty State
                    VStack {
                        Image(systemName: "bell.slash.fill")
                            .font(.largeTitle)
                            .foregroundColor(.gray)
                            .padding(.bottom, 8)
                        Text("No Notifications")
                            .font(.title2)
                        Text("You're all caught up! Check back later for updates.")
                            .multilineTextAlignment(.center)
                            .foregroundColor(.secondary)
                            .padding(.horizontal)
                    }
                    .accessibilityLabel("No notifications. You are all caught up.")
                } else {
                    // Success State: List of Notifications
                    List {
                        // Section for unread notifications
                        if !viewModel.notifications.filter({ !$0.isRead }).isEmpty {
                            Section(header: Text("Unread (\(viewModel.unreadCount))")) {
                                ForEach(viewModel.notifications.filter { !$0.isRead }) { notification in
                                    NotificationRow(notification: notification, markAsReadAction: viewModel.markAsRead)
                                }
                            }
                        }
                        
                        // Section for read notifications
                        if !viewModel.notifications.filter({ $0.isRead }).isEmpty {
                            Section(header: Text("Read")) {
                                ForEach(viewModel.notifications.filter { $0.isRead }) { notification in
                                    NotificationRow(notification: notification, markAsReadAction: viewModel.markAsRead)
                                }
                            }
                        }
                    }
                    .listStyle(.insetGrouped)
                    .refreshable {
                        // Support for pull-to-refresh
                        await viewModel.fetchNotifications()
                    }
                }
            }
            .navigationTitle("Notifications")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    HStack {
                        // Mark All Read Button
                        if viewModel.unreadCount > 0 {
                            Button {
                                viewModel.markAllAsRead()
                            } label: {
                                Label("Mark All Read", systemImage: "checkmark.circle.fill")
                            }
                            .accessibilityLabel("Mark all \(viewModel.unreadCount) notifications as read")
                        }
                        
                        // Settings Button (Navigation Support)
                        NavigationLink(destination: NotificationSettingsView()) {
                            Image(systemName: "gearshape")
                                .accessibilityLabel("Notification settings")
                        }
                    }
                }
            }
            // Initial data load
            .task {
                await viewModel.fetchNotifications()
            }
        }
    }
}

